data_t b_gn[N_OUT] = {0.01477260515093803406};

void run_validation(
    const char* name,
    int* data_gamma,
    int* data_neutron,
    int nTraces,
    data_t beta,
    data_t thr
) {
    std::cout << "\n--- Testing " << name << " Core (Scaling-Enabled) ---\n";

    data_t mem[N_OUT] = {0};
    spike_t spk[N_OUT] = {0};
    
    const data_t mem_decision_thr = (data_t)(-0.0625);
    const float scale_factor = 512.0;

    // Gamma samples (Expected Class 0)
    int gamma_correct = 0;
    for (int k = 0; k < nTraces; k++) {
        data_t x[N_IN];
        for (int i = 0; i < N_IN; i++) {
            // Apply 512.0 scaling
            x[i] = (data_t)((float)data_gamma[k * N_IN + i] / scale_factor);
        }
        
        mem[0] = 0; // Reset state for fresh trace
        net_linear_lif(x, W_gn, b_gn, mem, spk, beta, thr, RESET_ZERO, true);
        
        // Decision based on membrane potential
        int out_class = (mem[0] > mem_decision_thr) ? 1 : 0;
        if (out_class == 0) gamma_correct++;
    }

    // Neutron samples (Expected Class 1)
    int neutron_correct = 0;
    for (int k = 0; k < nTraces; k++) {
        data_t x[N_IN];
        for (int i = 0; i < N_IN; i++) {
            x[i] = (data_t)((float)data_neutron[k * N_IN + i] / scale_factor);
        }
        
        mem[0] = 0;
        net_linear_lif(x, W_gn, b_gn, mem, spk, beta, thr, RESET_ZERO, true);
        
        int out_class = (mem[0] > mem_decision_thr) ? 1 : 0;
        if (out_class == 1) neutron_correct++;
    }

    std::cout << "Results for " << name << ":\n";
    std::cout << "  Gamma Correct:   " << gamma_correct << " / " << nTraces << "\n";
    std::cout << "  Neutron Correct: " << neutron_correct << " / " << nTraces << "\n";
}

int main() {
    // Standard GN exercise parameters
    data_t beta = 0.9;
    data_t thr = 3500.0; // Higher threshold to avoid mid-trace firing if using membrane only

    run_validation("Gamma-Neutron", tracesGamma_gn, tracesNeutron_gn, 50, beta, thr);

    return 0;
}
